import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
function homePage(){
    const name = (
        <div id = "main">
            <head>
                <title>Home Page</title>
            </head>
            <div id = "home">
            <body>
                <h3>Hello React!</h3>
                <Profile/>
            </body>
            </div>
        </div>
    );
    ReactDOM.render(name, document.getElementById('root'))
}
setInterval(homePage, 0.01)
const data = <h3>Deez Nuts</h3>;
function getData(){
    var xhr = new XMLHttpRequest();
    xhr.open('GET', "http://localhost:8000/push", true)
    xhr.responseType = 'json';
    xhr.onload = function() {
        var status = xhr.status;
        if (status == 200){
            callback(null, xhr.response);
        } else {
            callback(status);
        }
    }
}
class Profile extends React.Component {
    render(){
         return data
    }
}
